SELECT id, order_no, user_id, pet_id, room_id, check_in, check_out, total_price, status, create_time, room_type_name, room_number, pet_name, coupon_id, coupon_amount, final_price
FROM boarding_order


        AND (order_no LIKE CONCAT('%',#{keyword},'%') OR room_type_name LIKE CONCAT('%',#{keyword},'%') OR room_number LIKE CONCAT('%',#{keyword},'%') OR pet_name LIKE CONCAT('%',#{keyword},'%'))


        AND status = #{status}


ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM boarding_order


        AND (order_no LIKE CONCAT('%',#{keyword},'%') OR room_type_name LIKE CONCAT('%',#{keyword},'%') OR room_number LIKE CONCAT('%',#{keyword},'%') OR pet_name LIKE CONCAT('%',#{keyword},'%'))


        AND status = #{status}
